# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any 
    
    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: '', description: 'Enter your build commands here')
        string(name: 'TEST_SCRIPT', defaultValue: '', description: 'Enter your test scripts here')
        string(name: 'DEPLOYMENT_STEPS', defaultValue: '', description: 'Enter your deployment steps here')
    }
    
    stages {
        stage('Build') {
            steps {
                script {
                    sh "${params.BUILD_COMMAND}"
                }
            }
        }
        
        stage('Test') {
            steps {
                script {
                    sh "${params.TEST_SCRIPT}"
                }
            }
        }
        
        stage('Deploy') {
            steps {
                script {
                    sh "${params.DEPLOYMENT_STEPS}"
                }
            }
        }
    }
}